mapper.select:
select A.*, B.username, B.avatar as cover, C.title, A.reply_to_id
from love_comment as A
         join love_user as B on (A.user_id=B.id)
         join love_thing as C on (A.thing_id=C.id)

    where A.thing_id=#{thingId}


    order by A.comment_time desc;


    order by A.like_count desc;

select A.*, B.username, C.title, C.cover, A.reply_to_id
from love_comment as A
join love_user as B on (A.user_id=B.id)
join love_thing as C on (A.thing_id=C.id)

    where A.user_id=#{userId}

    order by A.comment_time desc;

select A.*, B.username, B.avatar as cover, C.title
from love_comment as A
         join love_user as B on (A.user_id=B.id)
         join love_thing as C on (A.thing_id=C.id)
where A.reply_to_id=#{replyToId}
order by A.comment_time desc;
